class Solution(object):
    def maxFreeTime(self, eventTime, startTime, endTime):
        n = len(startTime)
        gaps = [startTime[0]]
        for i in range(1, n):
            gaps.append(startTime[i] - endTime[i - 1])
        gaps.append(eventTime - endTime[-1])

        durations = [endTime[i] - startTime[i] for i in range(n)]

        # prefix_max[i] = max gap in gaps[0..i-1]
        prefix_max = [0] * (n + 2)
        for i in range(n + 1):
            prefix_max[i + 1] = max(prefix_max[i], gaps[i])

        # suffix_max[i] = max gap in gaps[i..n]
        suffix_max = [0] * (n + 2)
        for i in range(n, -1, -1):
            suffix_max[i] = max(suffix_max[i + 1], gaps[i])

        ans = max(gaps)  # baseline: no meeting moved

        for i in range(n):
            d = durations[i]
            merged = gaps[i] + d + gaps[i + 1]  # removing meeting i merges its two adjacent gaps

            # Can we place meeting i somewhere outside [gaps[i], gaps[i+1]]?
            max_outside = max(prefix_max[i], suffix_max[i + 2])
            if max_outside >= d:
                ans = max(ans, merged)
            else:
                # Can we slide meeting i into its right gap?
                if gaps[i + 1] >= d:
                    ans = max(ans, gaps[i] + d)
                # Can we slide meeting i into its left gap?
                if gaps[i] >= d:
                    ans = max(ans, gaps[i + 1] + d)

        return ans
